/** Get all country names as a flat list (for dropdowns / autocomplete). */
export function getCountryOptions(): string[] {
  return worldCities.map((c) => c.country);
}

/** Get the cities array for a given country name. */
export function getCitiesForCountry(country: string): string[] {
  return worldCities.find((c) => c.country === country)?.cities ?? [];
}
